const vencimientos = $input.all().filter(item => item.json.concepto !== undefined && item.json.concepto !== null);

// Mensaje Luis - con formato completo y saltos de línea
let mensajeLuis = '⏰ *Recordatorio de vencimientos*\n\nTenés pagos próximos:\n\n';

// Mensaje Gonzalo - para el grupo
let mensajeGonzalo = '🏠 *Gastos del hogar*\n\nHola Gonza! Te paso lo que te corresponde pagar:\n\n';

let totalPesos = 0;
let totalUsd = 0;
let totalGonzalo = 0;
let hayCompartidos = false;

for (const item of vencimientos) {
  const v = item.json;
  const diasRestantes = Number(v.dias_restantes);
  const diasTexto = diasRestantes === 0 ? '🔴 HOY' :
                    diasRestantes === 1 ? '🟡 Mañana' :
                    `📅 En ${diasRestantes} días`;

  mensajeLuis += `${v.icono} *${v.concepto}*\n`;
  mensajeLuis += `   💰 ${v.moneda === 'USD' ? 'U$D' : '$'} ${Number(v.monto).toLocaleString('es-AR')}\n`;
  if (v.es_compartido) mensajeLuis += `   👥 Tu parte: $${(Number(v.monto) / 2).toLocaleString('es-AR')}\n`;
  mensajeLuis += `   ${diasTexto} (día ${v.dia_vencimiento})\n\n`;

  if (v.moneda === 'USD') totalUsd += Number(v.monto);
  else totalPesos += Number(v.monto);

  if (v.es_compartido) {
    hayCompartidos = true;
    const montoGonzalo = Number(v.monto) / 2;
    mensajeGonzalo += `${v.icono} *${v.concepto}*\n`;
    mensajeGonzalo += `   💰 $${montoGonzalo.toLocaleString('es-AR')}\n`;
    mensajeGonzalo += `   ${diasTexto} (día ${v.dia_vencimiento})\n\n`;
    totalGonzalo += montoGonzalo;
  }
}

mensajeLuis += '---\n';
if (totalPesos > 0) mensajeLuis += `Total ARS: $${totalPesos.toLocaleString('es-AR')}\n`;
if (totalUsd > 0) mensajeLuis += `Total USD: U$D ${totalUsd.toLocaleString('es-AR')}\n`;

if (hayCompartidos) {
  mensajeGonzalo += `---\n💵 *Tu total: $${totalGonzalo.toLocaleString('es-AR')}*\n\n`;
  mensajeGonzalo += '📲 Alias: LMOLINARE3271.NX.ARS';
}

return { mensajeLuis, mensajeGonzalo, hayCompartidos };
